class Solution:
    def maxHeightOfTriangle(self, red: int, blue: int) -> int:
        def height(a, b):
            # a on odd rows (1,3,5,...), b on even rows (2,4,6,...)
            h = 0
            ra, rb = a, b
            row = 1
            while True:
                if row % 2 == 1:
                    if ra < row:
                        break
                    ra -= row
                else:
                    if rb < row:
                        break
                    rb -= row
                h += 1
                row += 1
            return h
        return max(height(red, blue), height(blue, red))

