class Solution:
    def maxHeightOfTriangle(self, red: int, blue: int) -> int:
        def sim(a, b):
            ra, rb, row = a, b, 1
            while True:
                if row % 2 == 1:
                    if ra < row: return row - 1
                    ra -= row
                else:
                    if rb < row: return row - 1
                    rb -= row
                row += 1
        return max(sim(red, blue), sim(blue, red))

